"use client";

import { useState } from "react";
import Link from "next/link";
import { Mail, ArrowRight, CheckCircle2 } from "lucide-react";
import { supabase } from "@/lib/supabase";

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState("");
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleReset = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Send password reset email
    const { error: resetError } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/update-password`,
    });

    if (resetError) {
      setError(resetError.message);
    } else {
      setSuccess(true);
    }
    setLoading(false);
  };

  return (
    <div className="glass-panel p-8 md:p-10 rounded-2xl w-full flex flex-col gap-6">
      <div className="text-center mb-2">
        <h2 className="text-3xl font-bold text-white mb-2">Reset Password</h2>
        <p className="text-zinc-400">We'll send you a secure link to reset it.</p>
      </div>

      {error && (
        <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-lg text-sm text-center">
          {error}
        </div>
      )}

      {success ? (
        <div className="bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 p-6 rounded-2xl flex flex-col items-center justify-center text-center gap-3">
          <CheckCircle2 size={48} className="text-emerald-400" />
          <h3 className="text-xl font-bold text-white mt-2">Check Your Email</h3>
          <p className="text-sm">We've sent a password reset link to {email}. Please click the link to choose a new password.</p>
          <Link href="/login" className="mt-4 bg-emerald-500/20 hover:bg-emerald-500/30 text-emerald-400 px-6 py-2 rounded-xl transition-colors font-medium">
            Return to Login
          </Link>
        </div>
      ) : (
        <form onSubmit={handleReset} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-zinc-300" htmlFor="email">Registered Email Address</label>
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={20} />
              <input
                id="email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all"
                placeholder="you@example.com"
              />
            </div>
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full group relative inline-flex items-center justify-center gap-2 px-6 py-3.5 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-semibold transition-all shadow-[0_0_15px_rgba(16,185,129,0.2)] disabled:opacity-70 disabled:cursor-not-allowed cursor-pointer"
          >
            <span>{loading ? "Sending Link..." : "Send Reset Link"}</span>
            {!loading && <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />}
          </button>
        </form>
      )}

      {!success && (
        <div className="mt-2 text-center text-sm text-zinc-400">
          Remembered your password?{" "}
          <Link href="/login" className="text-emerald-400 font-medium hover:text-emerald-300 transition-colors">
            Sign in
          </Link>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { Mail, Lock, ArrowRight } from "lucide-react";
import { supabase } from "@/lib/supabase";

export default function LoginPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    if (error) {
      setError(error.message);
      setLoading(false);
    } else {
      window.location.href = "/dashboard";
    }
  };

  return (
    <div className="glass-panel p-8 md:p-10 rounded-2xl w-full flex flex-col gap-6">
      <div className="text-center mb-2">
        <h2 className="text-3xl font-bold text-white mb-2">Welcome Back</h2>
        <p className="text-zinc-400">Sign in to your account</p>
      </div>

      {error && (
        <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-lg text-sm text-center">
          {error}
        </div>
      )}

      <form onSubmit={handleLogin} className="space-y-6">
        <div className="space-y-2">
          <label className="text-sm font-medium text-zinc-300" htmlFor="email">Email Address</label>
          <div className="relative">
            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={20} />
            <input
              id="email"
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all"
              placeholder="you@example.com"
            />
          </div>
        </div>

        <div className="space-y-2">
          <div className="flex justify-between items-center">
            <label className="text-sm font-medium text-zinc-300" htmlFor="password">Password</label>
            <Link href="/forgot-password" className="text-xs text-emerald-400 hover:text-emerald-300 transition-colors">
              Forgot password?
            </Link>
          </div>
          <div className="relative">
            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={20} />
            <input
              id="password"
              type="password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all"
              placeholder="••••••••"
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={loading}
          className="w-full group relative inline-flex items-center justify-center gap-2 px-6 py-3.5 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-semibold transition-all shadow-[0_0_15px_rgba(16,185,129,0.2)] disabled:opacity-70 disabled:cursor-not-allowed cursor-pointer"
        >
          <span>{loading ? "Signing in..." : "Sign In"}</span>
          {!loading && <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />}
        </button>
      </form>

      <div className="mt-2 text-center text-sm text-zinc-400">
        Don&apos;t have an account?{" "}
        <Link href="/signup" className="text-emerald-400 font-medium hover:text-emerald-300 transition-colors">
          Create one now
        </Link>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Dna, Play, CheckCircle2, AlertTriangle, Dice5, FileLock } from "lucide-react";
import { supabase } from "@/lib/supabase";

export default function DrawEnginePage() {
  const [isSimulating, setIsSimulating] = useState(false);
  const [activePool, setActivePool] = useState(0);
  const [simResults, setSimResults] = useState<{
    numbers: number[];
    pool: number;
    winners: { match5: number, match4: number, match3: number };
  } | null>(null);

  useEffect(() => {
    // Fetch the pending total pool from the database
    const fetchActivePool = async () => {
      const { data } = await supabase
        .from('draws')
        .select('total_pool')
        .eq('status', 'pending')
        .limit(1)
        .single();

      if (data) setActivePool(data.total_pool || 0);
    };
    fetchActivePool();
  }, []);

  const runSimulation = () => {
    setIsSimulating(true);
    setSimResults(null);

    // In a real algorithmic draw, we would call an edge function here
    // For now, doing a client-side random simulation logic for the PRD standard lottery options
    setTimeout(() => {
      const numbers = [];
      while(numbers.length < 5) {
        let r = Math.floor(Math.random() * 45) + 1;
        if(numbers.indexOf(r) === -1) numbers.push(r);
      }

      setSimResults({
        numbers,
        pool: activePool || 12450, // fallback if no DB connection
        winners: { match5: 0, match4: Math.floor(Math.random() * 5), match3: Math.floor(Math.random() * 50) + 10 }
      });
      setIsSimulating(false);
    }, 1500);
  };

  const publishDraw = async () => {
    if (!simResults) return;
    setIsSimulating(true);

    const { error } = await supabase
      .from('draws')
      .update({
        winning_numbers: simResults.numbers,
        pool_5_match: simResults.pool * 0.4,
        pool_4_match: simResults.pool * 0.35,
        pool_3_match: simResults.pool * 0.25,
        status: 'published',
        drawn_at: new Date().toISOString()
      })
      .eq('status', 'pending');

    if (error) {
      alert("Error publishing draw: " + error.message);
    } else {
      alert("Draw successfully published! Subscriptions will be notified.");
      setSimResults(null);
      setActivePool(0); // It will reset to a new pending draw via triggers ideally
    }
    setIsSimulating(false);
  };

  return (
    <div className="flex flex-col gap-6 animate-fade-in-up">
      <div>
        <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
          <Dna className="text-rose-400" /> Draw Simulation Engine
        </h1>
        <p className="text-zinc-400">Run simulations, review distributions, and publish official monthly draw results.</p>
      </div>

      <div className="grid md:grid-cols-2 gap-6 mt-4">

        {/* Configuration Panel */}
        <div className="glass-panel p-6 rounded-2xl flex flex-col gap-6">
          <h3 className="text-lg font-semibold text-white border-b border-white/10 pb-4">Draw Configuration</h3>

          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-zinc-400 block mb-2">Draw Logic Algorithm</label>
              <div className="grid grid-cols-2 gap-3">
                <button className="bg-rose-500/10 border border-rose-500/50 text-rose-400 px-4 py-3 rounded-xl font-medium flex items-center justify-center gap-2 cursor-pointer">
                  <Dice5 size={18} /> True Random
                </button>
                <button className="bg-white/5 border border-white/10 text-zinc-400 px-4 py-3 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-white/10 cursor-pointer">
                  <FileLock size={18} /> Algorithmic
                </button>
              </div>
              <p className="text-xs text-zinc-500 mt-2">Currently using the standard lottery-style random generator (1-45).</p>
            </div>

            <div className="bg-white/5 p-4 rounded-xl border border-white/10 mt-6">
              <span className="block text-sm text-zinc-400 mb-1">Current Pending Pool</span>
              <span className="text-3xl font-bold text-white">${activePool.toLocaleString(undefined, {minimumFractionDigits: 2})}</span>
            </div>
          </div>

          <div className="mt-auto pt-6 border-t border-white/10">
            <button 
              onClick={runSimulation}
              disabled={isSimulating}
              className="w-full bg-zinc-100 hover:bg-white text-zinc-900 font-bold py-4 rounded-xl flex items-center justify-center gap-2 shadow-[0_0_20px_rgba(255,255,255,0.1)] transition-all disabled:opacity-50 cursor-pointer"
            >
              {isSimulating ? "Running Simulation..." : <><Play size={18} /> Run Pre-Draw Simulation</>}
            </button>
          </div>
        </div>

        {/* Results Panel */}
        <div className="glass-panel p-6 rounded-2xl flex flex-col relative overflow-hidden">
          <h3 className="text-lg font-semibold text-white border-b border-white/10 pb-4 mb-6">Simulation Results</h3>

          {!simResults && !isSimulating && (
             <div className="flex-1 flex flex-col items-center justify-center text-zinc-500">
               <Dna size={48} className="mb-4 opacity-50" />
               <p>Run a simulation to view estimated results</p>
             </div>
          )}

          {isSimulating && !simResults && (
            <div className="flex-1 flex flex-col items-center justify-center text-rose-400">
               <div className="w-12 h-12 border-4 border-rose-500/30 border-t-rose-500 rounded-full animate-spin mb-4"></div>
               <p className="animate-pulse">Calculating probability matrix... This queries the profiles & scores.</p>
             </div>
          )}

          {simResults && !isSimulating && (
            <div className="flex flex-col h-full animate-fade-in-up">
              <div className="flex justify-between gap-2 mb-8">
                {simResults.numbers.map((num, i) => (
                  <div key={i} className="flex-1 aspect-square rounded-full bg-rose-500/10 border border-rose-500/30 flex items-center justify-center text-2xl font-bold text-white shadow-[0_0_15px_rgba(225,29,72,0.2)]">
                    {num}
                  </div>
                ))}
              </div>

              <div className="space-y-3 mb-6">
                <div className="flex justify-between p-3 rounded-lg bg-white/5 border border-white/5">
                  <span className="text-zinc-300">Total Prize Pool</span>
                  <span className="text-white font-bold">${simResults.pool.toLocaleString(undefined, {minimumFractionDigits: 2})}</span>
                </div>

                <div className="flex justify-between items-center p-3 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
                  <div>
                    <span className="text-emerald-400 font-medium block">5-Number Match (40%)</span>
                    <span className="text-xs text-emerald-100/70">{simResults.winners.match5} Winners</span>
                  </div>
                  <div className="text-right">
                    <span className="text-white font-bold">${(simResults.pool * 0.4).toLocaleString(undefined, {minimumFractionDigits: 2})}</span>
                    {simResults.winners.match5 === 0 && <span className="block text-xs text-amber-400">Rollover to next month</span>}
                  </div>
                </div>

                <div className="flex justify-between items-center p-3 rounded-lg bg-white/5 border border-white/5">
                  <div>
                    <span className="text-zinc-300 font-medium block">4-Number Match (35%)</span>
                    <span className="text-xs text-zinc-400">{simResults.winners.match4} Winners</span>
                  </div>
                  <span className="text-white font-bold">${(simResults.pool * 0.35).toLocaleString(undefined, {minimumFractionDigits: 2})}</span>
                </div>

                <div className="flex justify-between items-center p-3 rounded-lg bg-white/5 border border-white/5">
                  <div>
                    <span className="text-zinc-300 font-medium block">3-Number Match (25%)</span>
                    <span className="text-xs text-zinc-400">{simResults.winners.match3} Winners</span>
                  </div>
                  <span className="text-white font-bold">${(simResults.pool * 0.25).toLocaleString(undefined, {minimumFractionDigits: 2})}</span>
                </div>
              </div>

              <div className="mt-auto">
                <div className="bg-amber-500/10 border border-amber-500/20 p-3 rounded-lg flex items-start gap-3 mb-4">
                  <AlertTriangle className="text-amber-400 shrink-0 mt-0.5" size={16} />
                  <p className="text-xs text-amber-100/80">
                    Publishing the draw will lock the numbers and notify all matching subscribers. This action is irreversible.
                  </p>
                </div>
                <button 
                  onClick={publishDraw}
                  className="w-full bg-rose-500 hover:bg-rose-600 text-white font-semibold py-4 rounded-xl flex items-center justify-center gap-2 shadow-[0_0_15px_rgba(225,29,72,0.3)] transition-all cursor-pointer"
                >
                  <CheckCircle2 size={18} /> Publish Official Draw
                </button>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Search, Edit2, ShieldAlert } from "lucide-react";
import { supabase } from "@/lib/supabase";

type ProfileRow = {
  id: string;
  email: string;
  role: string;
  subscription_status: string;
  created_at: string;
};

export default function UsersManagementPage() {
  const [users, setUsers] = useState<ProfileRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    const fetchUsers = async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .order('created_at', { ascending: false });

      if (data) setUsers(data);
      setLoading(false);
    };

    fetchUsers();
  }, []);

  const filteredUsers = users.filter((u) => u.email?.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="flex flex-col gap-6 animate-fade-in-up">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white mb-2">Subscriber Management</h1>
          <p className="text-zinc-400">View and manage all registered users, their subscription status, and scores.</p>
        </div>
        <button className="bg-rose-500 hover:bg-rose-600 text-white px-4 py-2 rounded-xl text-sm font-semibold transition-colors flex items-center justify-center gap-2 whitespace-nowrap shadow-[0_0_15px_rgba(225,29,72,0.2)] cursor-pointer">
          Export Members List
        </button>
      </div>

      <div className="glass-panel p-6 rounded-2xl">
        <div className="flex items-center mb-6">
          <div className="relative w-full max-w-sm">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-lg py-2.5 pl-10 pr-4 text-sm text-white placeholder-zinc-500 focus:outline-none focus:ring-1 focus:ring-rose-500/50"
              placeholder="Search by email..."
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-white/10 text-xs uppercase text-zinc-500 font-medium tracking-wider">
                <th className="pb-3 px-4">Member Email</th>
                <th className="pb-3 px-4">Status</th>
                <th className="pb-3 px-4">Role</th>
                <th className="pb-3 px-4">Joined</th>
                <th className="pb-3 px-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="text-sm">
              {loading ? (
                <tr><td colSpan={5} className="text-center text-zinc-500 py-8">Loading users...</td></tr>
              ) : filteredUsers.length === 0 ? (
                <tr><td colSpan={5} className="text-center text-zinc-500 py-8">No members found.</td></tr>
              ) : filteredUsers.map((user) => (
                <tr key={user.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                  <td className="py-4 px-4 text-white font-medium">{user.email}</td>
                  <td className="py-4 px-4">
                    <span className={`px-2.5 py-1 rounded-full text-xs font-semibold ${
                      user.subscription_status === 'active' 
                        ? 'bg-emerald-500/10 text-emerald-400' 
                        : 'bg-zinc-800 text-zinc-400'
                    }`}>
                      {user.subscription_status || 'inactive'}
                    </span>
                  </td>
                  <td className="py-4 px-4 text-zinc-300 capitalize">{user.role}</td>
                  <td className="py-4 px-4 text-zinc-400">{new Date(user.created_at).toLocaleDateString()}</td>
                  <td className="py-4 px-4 text-right">
                    <button className="p-2 text-zinc-400 hover:text-white hover:bg-white/10 rounded-lg transition-colors cursor-pointer">
                      <Edit2 size={16} />
                    </button>
                    <button className="p-2 text-rose-400 hover:text-rose-300 hover:bg-rose-500/10 rounded-lg transition-colors ml-1 cursor-pointer">
                      <ShieldAlert size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { CheckCircle2, XCircle, Search, Eye, Filter } from "lucide-react";
import { supabase } from "@/lib/supabase";

type PendingVerificationType = {
  id: string;
  user_id: string;
  match_type: number;
  amount: number;
  verification_image_url: string;
  created_at: string;
  profiles?: { email: string };
};

export default function VerificationPage() {
  const [pending, setPending] = useState<PendingVerificationType[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    const fetchPending = async () => {
      const { data } = await supabase
        .from('winnings')
        .select(`
          *,
          profiles(email)
        `)
        .eq('status', 'pending')
        .not('verification_image_url', 'is', null)
        .order('created_at', { ascending: true });

      if (data) setPending(data as unknown as PendingVerificationType[]);
      setLoading(false);
    };

    fetchPending();
  }, []);

  const handleAction = async (id: string, newStatus: 'paid' | 'rejected') => {
    if(!confirm(`Are you sure you want to mark this as ${newStatus}?`)) return;

    // Optimistic UI update
    setPending(prev => prev.filter(p => p.id !== id));

    const { error } = await supabase
      .from('winnings')
      .update({ status: newStatus })
      .eq('id', id);

    if (error) {
      alert("Failed to update status: " + error.message);
      // Rollback (omitted for brevity)
    }
  };

  const filtered = pending.filter(p => p.id.includes(search) || p.profiles?.email?.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="flex flex-col gap-6 animate-fade-in-up">
      <div>
        <h1 className="text-3xl font-bold text-white mb-2">Winner Verification</h1>
        <p className="text-zinc-400">Review uploaded score screenshots from members to approve and release draw payouts.</p>
      </div>

      <div className="glass-panel p-6 rounded-2xl mt-4">

        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-semibold text-white">Pending Reviews ({pending.length})</h3>
          <div className="flex gap-2">
            <div className="relative w-64 hidden sm:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
              <input
                type="text"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-lg py-2 pl-10 pr-4 text-sm text-white placeholder-zinc-500 focus:outline-none focus:ring-1 focus:ring-rose-500/50"
                placeholder="Search ID or Email"
              />
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-white/10 text-xs uppercase text-zinc-500 font-medium">
                <th className="pb-3 px-4">Transaction ID</th>
                <th className="pb-3 px-4">Member Email</th>
                <th className="pb-3 px-4">Match Tier</th>
                <th className="pb-3 px-4">Payout Amount</th>
                <th className="pb-3 px-4 text-center">Proof Document</th>
                <th className="pb-3 px-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="text-sm">
              {loading ? (
                <tr><td colSpan={6} className="text-center py-8 text-zinc-500">Loading verifications...</td></tr>
              ) : filtered.length === 0 ? (
                <tr><td colSpan={6} className="text-center py-12 text-zinc-500">No pending verifications with uploads found.</td></tr>
              ) : filtered.map((item) => (
