"use client";

import { useState, useEffect } from "react";
import { Plus, Target, CalendarDays, History } from "lucide-react";
import { supabase } from "@/lib/supabase";

type ScoreEntry = {
  id: string;
  score: number;
  date: string;
  created_at: string;
};

export default function ScoresPage() {
  const [scores, setScores] = useState<ScoreEntry[]>([]);
  const [newScore, setNewScore] = useState("");
  const [newDate, setNewDate] = useState("");
  const [loading, setLoading] = useState(false);
  const [loadingData, setLoadingData] = useState(true);
  const [userId, setUserId] = useState<string | null>(null);

  useEffect(() => {
    const fetchScores = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        setLoadingData(false);
        return;
      }
      setUserId(session.user.id);

      const { data, error } = await supabase
        .from('scores')
        .select('*')
        .eq('user_id', session.user.id)
        .order('date', { ascending: false })
        .order('created_at', { ascending: false })
        .limit(5);

      if (data) setScores(data);
      setLoadingData(false);
    };

    fetchScores();
  }, []);

  const handleAddScore = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newScore || !newDate || !userId) return;

    const scoreNum = parseInt(newScore);
    if (scoreNum < 1 || scoreNum > 45) {
      alert("Stableford score must be between 1 and 45.");
      return;
    }

    setLoading(true);

    const { data, error } = await supabase
      .from('scores')
      .insert([{ user_id: userId, score: scoreNum, date: newDate }])
      .select();

    if (error) {
      alert("Error adding score: " + error.message);
    } else if (data && data.length > 0) {
      // Re-fetch to rely on DB's limit 5 trigger
      const { data: updatedScores } = await supabase
        .from('scores')
        .select('*')
        .eq('user_id', userId)
        .order('date', { ascending: false })
        .order('created_at', { ascending: false })
        .limit(5);

      if (updatedScores) setScores(updatedScores);
      setNewScore("");
      setNewDate("");
    }

    setLoading(false);
  };

  return (
    <div className="flex flex-col gap-6 animate-fade-in-up">
      <div>
        <h1 className="text-3xl font-bold text-white mb-2">Performance Tracking</h1>
        <p className="text-zinc-400">Log your Stableford scores. The latest 5 entries determine your mechanical draw numbers.</p>
      </div>

      <div className="grid md:grid-cols-5 gap-6">

        {/* Active Numbers Display */}
        <div className="md:col-span-12 w-full glass-panel p-6 rounded-2xl flex flex-col md:flex-row items-center justify-between gap-6 border-emerald-500/20">
          <div>
            <div className="flex items-center gap-2 text-emerald-400 font-medium mb-1">
              <Target size={18} />
              <span>Current Draw Numbers</span>
            </div>
            <p className="text-sm text-zinc-400">These will be used in the next draw.</p>
          </div>

          <div className="flex gap-2 sm:gap-4 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
            {loadingData ? (
               <div className="text-sm text-emerald-400">Loading scores...</div>
            ) : (
               <>
                 {scores.slice(0, 5).map((score) => (
                   <div key={score.id} className="w-14 h-14 md:w-16 md:h-16 shrink-0 rounded-full bg-emerald-500/10 border border-emerald-500/30 flex items-center justify-center text-xl font-bold text-white shadow-[0_0_15px_rgba(16,185,129,0.1)]">
                     {score.score}
                   </div>
                 ))}
                 {/* Fill empty spots if less than 5 */}
                 {Array.from({ length: 5 - scores.length }).map((_, i) => (
                   <div key={`empty-${i}`} className="w-14 h-14 md:w-16 md:h-16 shrink-0 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-xl font-bold text-zinc-600 border-dashed">
                     -
                   </div>
                 ))}
               </>
            )}
          </div>
        </div>

        {/* Add Score Form */}
        <div className="md:col-span-2 flex flex-col gap-6">
          <div className="glass-panel p-6 rounded-2xl">
            <h3 className="text-lg font-semibold text-white mb-6 flex items-center gap-2">
              <Plus size={18} className="text-emerald-400" />
              <span>Log New Score</span>
            </h3>

            <form onSubmit={handleAddScore} className="space-y-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-zinc-300">Stableford Points (1-45)</label>
                <div className="relative">
                  <Target className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
                  <input
                    type="number"
                    min="1"
                    max="45"
                    required
                    value={newScore}
                    onChange={(e) => setNewScore(e.target.value)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50"
                    placeholder="e.g. 36"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-zinc-300">Date Played</label>
                <div className="relative">
                  <CalendarDays className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
                  <input
                    type="date"
                    required
                    value={newDate}
                    onChange={(e) => setNewDate(e.target.value)}
                    className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 [color-scheme:dark]"
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={loading || !userId}
                className="w-full mt-2 bg-emerald-500 hover:bg-emerald-600 text-white py-3 rounded-xl font-semibold transition-all shadow-[0_0_15px_rgba(16,185,129,0.2)] disabled:opacity-70 cursor-pointer"
              >
                {loading ? "Adding..." : "Add Score"}
              </button>
            </form>
          </div>
        </div>

        {/* Score History */}
        <div className="md:col-span-3 glass-panel p-6 rounded-2xl flex flex-col h-[400px]">
          <h3 className="text-lg font-semibold text-white mb-6 flex items-center gap-2">
            <History size={18} className="text-emerald-400" />
            <span>Score History</span>
          </h3>

          <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
            {loadingData ? (
              <div className="text-zinc-500 text-center py-8">Loading...</div>
            ) : scores.map((score, index) => (
              <div key={score.id} className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center justify-between">
                <div>
                  <div className="text-white font-medium">{score.score} Points</div>
                  <div className="text-xs text-zinc-400 mt-1">{new Date(score.date).toLocaleDateString(undefined, { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' })}</div>
                </div>
                {index === 0 && (
                  <span className="text-xs font-medium text-emerald-400 bg-emerald-500/10 px-2 py-1 rounded-md">
                    Latest
                  </span>
                )}
              </div>
            ))}
            {!loadingData && scores.length === 0 && (
              <div className="text-center text-zinc-500 py-8">
                No scores recorded yet.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

