              onClick={() => setSelectedPlan("yearly")}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-all ${
                selectedPlan === "yearly" ? "bg-emerald-500 text-white shadow-lg" : "text-zinc-400 hover:text-white"
              }`}
            >
              Yearly <span className="text-xs text-emerald-200 ml-1">Save 15%</span>
            </button>
          </div>

          <div className="flex flex-col mt-4">
            <span className="text-zinc-400 text-sm font-medium">Platform Access</span>
            <div className="flex items-end gap-2 my-2">
              <span className="text-4xl font-bold text-white">
                ${selectedPlan === "monthly" ? "20" : "200"}
              </span>
              <span className="text-zinc-500 mb-1">/{selectedPlan === "monthly" ? "mo" : "yr"}</span>
            </div>

            <ul className="mt-6 space-y-4">
              {[
                "Unlimited 5-score rolling tracking",
                "Automatic entry into monthly draw",
                "Direct automated charity donations",
                "Community impact reports"
              ].map((text, i) => (
                <li key={i} className="flex items-start gap-3 text-sm text-zinc-300">
                  <CheckCircle2 size={18} className="text-emerald-400 shrink-0 mt-0.5" />
                  <span>{text}</span>
                </li>
              ))}
            </ul>
          </div>
        </div>

        {/* Payment Logic / CTA */}
        <div className="glass-panel p-6 rounded-2xl flex flex-col justify-between">
          <div className="space-y-6">
            <div className="flex items-center gap-3 text-white font-medium pb-4 border-b border-white/10">
              <CreditCard size={20} className="text-emerald-400" />
              <span>Secure Checkout</span>
            </div>

            <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-xl p-4 flex gap-3">
              <ShieldCheck size={24} className="text-emerald-400 shrink-0" />
              <div>
                <h4 className="text-sm text-emerald-400 font-medium mb-1">PCI-Compliant</h4>
                <p className="text-xs text-emerald-100/70 leading-relaxed">
                  Payments are processed securely via Stripe. We do not store your credit card details on our servers.
                </p>
              </div>
            </div>
          </div>

          <button 
            onClick={handleSubscribe}
            disabled={loading}
            className="w-full mt-8 group relative inline-flex items-center justify-center gap-2 px-6 py-4 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-semibold transition-all shadow-[0_0_15px_rgba(16,185,129,0.2)] disabled:opacity-70"
          >
            <span>{loading ? "Redirecting to Stripe..." : "Continue to Payment"}</span>
            {!loading && <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />}
          </button>
        </div>
      </div>
    </div>
  );
}
